  ('customs-f19eb2bd-moex-00507', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '航行中之動力船舶於夜間突然主機故障，船舶操控失靈，在水中仍有移動速度，應懸掛之燈號：', '["兩盞桅燈、舷燈、艉燈、垂直兩盞環照紅燈", "僅顯示垂直兩盞環照紅燈，其他號燈關閉", "舷燈、艉燈、垂直兩盞環照紅燈", "舷燈、垂直兩盞環照紅燈"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00508', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '一艘動力船舶於夜間除航行燈與其他燈號外，又顯示垂直三盞環照紅燈，這表示它是：', '["擱淺船舶", "操縱失靈船舶", "受吃水限制船舶", "從事清掃水雷作業船舶"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00509', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '負責航行當值的航行員應：', '["船長或引水人負責操縱時，當值航行員的瞭望職責即被解除", "集中精神保持正確瞭望，不做與當值無關的事情", "沿岸航行時，每半點或整點進入海圖室進行定位", "當值航行員進入海圖室定位，必須有甲級船員協助或代替其履行瞭望的義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00510', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '依我國船員法規定，下列何者描述為不符法規要求？', '["船舶有急迫危險時，船長應盡力採取必要之措施，救助人命", "船長在航行中不論遇何危險，得依其職權獨自立即決定放棄船舶", "放棄船舶時，船長應盡力將金錢及貴重物救出", "船長違反"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00511', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '依據SOLAS公約規定，在短程國際航程作業之船舶，如其港口船席佈置及營運形式不容許某一舷之救生 艇下水者，主管官署得准許該舷之救生艇不下水。但所有該等救生艇至少多久應降落一次？並至少多久應 下水一次？', '["每個月/3個月", "3個月/6個月", "3個月/每年", "6個月/每年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00512', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '依據SOLAS公約規定，如屬合理可行，除兼作救難艇之救生艇外，救難艇應多久連同其指定船員一起下 水，並在水上操艇？在任何狀況下，本規定至少多久應施行一次？', '["每個月/3個月", "3個月/6個月", "3個月/每年", "6個月/每年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00513', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '依據SOLAS公約第III章規則13對於救生艇施放的相關規定，要求救生艇必須能在船舶俯仰差達到多少 度及左右傾側達到多少度的不利狀態下，仍能順利的將艇筏放入水中？', '["5°/10°", "7°/15°", "10°/20°", "15°/25°"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00514', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '船舶在港內停靠碼頭期間發生火災時，在滅火過程中船上應進行的工作項目中下列何者錯誤？', '["與港務當局、港口警察保持隨時聯繫", "港口消防隊對船舶滅火負有主要責任", "查清所有在船人員", "隨時做好離港的準備"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00515', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '當本船於港內靠泊時他船因拖錨而移向本船之應急措施，下列何者錯誤？', '["全船應立即依「救生部署表」執行", "立即報告船長並通知其他船員立即備便主機，駕駛臺、船艏及船艉緊急備便因應", "連鳴五短聲，以警告拖錨之他船儘早注意避讓", "緊急通知港務當局，並請求拖船協助"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00516', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-606c6876', 'sub-customs-f19eb2bd-03', NULL, 'single_choice', '依據SOLAS公約及其修訂，貨船在港期間船員人數調動超過多少比例時，應於離港多少時間內召集進行 救生艇與滅火演習？', '["15%，8小時", "20%，12小時", "25%，24小時", "30%，48小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "6e762480a360", "answer_pdf_sha1": "ac729eceebc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航行當值大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
